import React from "react";


export const SoldItems = ({ props }) => {
  return (
    <div className="">
        <h1>
          Clothes Sold {props.iname} {props.imrp}
        </h1>
        <div className="">
          {props.photos && (
            <div className="h-32 flex" key={props._id}>
              <img
                className="rounded-2xl w-full object-cover"
                alt="img not found"
                src={"http://localhost:5000/" + props.photos[0]}
              />
            </div>
          )}
        </div>
    </div>
  );
};
